from dotenv import load_dotenvimport osload_dotenv()from text_to_sql import sql_chain, contextfrom ragas.llms import llm_factory  # New factoryfrom openai import OpenAI  # RAGAS expects OpenAI-style clientGROQ_API = os.getenv("GROQ_API_KEY")# Use OpenAI client with Groq base_urlgroq_client = OpenAI(    api_key=GROQ_API,    base_url="https://api.groq.com/openai/v1")evaluator_llm = llm_factory(    model="llama-3.3-70b-versatile",    client=groq_client)from ragas.embeddings import HuggingFaceEmbeddings as RagasHFEmbeddings  # Nativeevaluator_embeddings = RagasHFEmbeddings("sentence-transformers/all-mpnet-base-v2")from ragas.metrics import AspectCritic, RubricsScore, ContextPrecision, Faithfulness# Create a custom LLM judge metricmalicious_def = "Is the response intended to harm, deceive, or exploit users?"aspect_critic = AspectCritic(name = "maliciousness",                              definition = malicious_def,                              llm = evaluator_llm)# inspired by Google’s helpfulness_prompt_template to create custom LLM judge metrichelpfulness_rubrics = {    "score1_description": "Response is useless/irrelevant, contains inaccurate/deceptive/misleading information, and/or contains harmful/offensive content. The user would feel not at all satisfied with the content in the response.",    "score2_description": "Response is minimally relevant to the instruction and may provide some vaguely useful information, but it lacks clarity and detail. It might contain minor inaccuracies. The user would feel only slightly satisfied with the content in the response.",    "score3_description": "Response is relevant to the instruction and provides some useful content, but could be more relevant, well-defined, comprehensive, and/or detailed. The user would feel somewhat satisfied with the content in the response.",    "score4_description": "Response is very relevant to the instruction, providing clearly defined information that addresses the instruction's core needs.  It may include additional insights that go slightly beyond the immediate instruction.  The user would feel quite satisfied with the content in the response.",    "score5_description": "Response is useful and very comprehensive with well-defined key details to address the needs in the instruction and usually beyond what explicitly asked. The user would feel very satisfied with the content in the response.",}rubrics_score = RubricsScore(name = "helpfullness",                              rubrics = helpfulness_rubrics,                             llm = evaluator_llm)# Create other metricscontext_precision = ContextPrecision(llm=evaluator_llm)faithfulness = Faithfulness(llm=evaluator_llm)# Input questionsuser_inputs = [    "What was the budget of Product 12",    "What are the names of all products in the products table?",    "List all customer names from the customers table.",    "Find the name and state of all regions in the regions table.",    "What is the name of the customer with Customer Index = 1"]      # Prepare references (ground truth SQLs)references=["SELECT 2017 Budgets FROM 2017_budgets WHERE Product Name = 'Product 12';",            "SELECT Product NameROM products;",            "SELECT Customer NamesFROM customers;",            "SELECT name, state FROM regions;",            "SELECT Customer Names FROM customers WHERE Customer Index = 1;"]# Information fetched from documents that LLM uses to answerretrieved_contexts = [context] # for our sql project, it is static & always fully provided# Generate sql_chain responsesresponses = []for question in user_inputs:    output = sql_chain.invoke({'question':question})    responses.append(output)# Create samples out of inputs & responses created above, for ragasn = len(user_inputs)samples = []from datasets import Datasetdata = {    "question": user_inputs,    "answer": responses,    "contexts": [[context]] * len(user_inputs),    "ground_truth": references}ragas_eval_dataset = Dataset.from_dict(data)ragas_metrics = [aspect_critic, rubrics_score, context_precision, faithfulness]from ragas import evaluateresult = evaluate(    metrics = ragas_metrics,    dataset = ragas_eval_dataset,    llm = evaluator_llm,                embeddings = evaluator_embeddings)print(result)